const now = new Date();
// Get "today" in PT
const ptStr = now.toLocaleString('en-US', { timeZone: 'America/Los_Angeles' });
const ptNow = new Date(ptStr);
const yesterday = new Date(ptNow);
yesterday.setDate(yesterday.getDate() - 1);

const pad = (n) => String(n).padStart(2, '0');
const yStr = `${yesterday.getFullYear()}-${pad(yesterday.getMonth()+1)}-${pad(yesterday.getDate())}`;
const tStr = `${ptNow.getFullYear()}-${pad(ptNow.getMonth()+1)}-${pad(ptNow.getDate())}`;

const base = 'https://rhrlnkbphxntxxxcrgvv.supabase.co/rest/v1';

return [{ json: {
  messagesUrl: `${base}/messages?select=id,user_id,message_type,direction,content,sent_at,metadata&sent_at=gte.${yStr}T00:00:00&sent_at=lt.${tStr}T00:00:00&order=sent_at.desc&limit=5000`,
  usersUrl: `${base}/users?select=id,email,assistant_name,onboarding_state&onboarding_state=eq.complete`,
  yesterdayStr: yStr,
  todayStr: tStr,
}}];

// Build daily usage report from Supabase messages + users data
const messages = $('Fetch Messages').all().map(i => i.json);
const allMessages = Array.isArray(messages[0]) ? messages[0] : messages;
const users = $('Fetch Users').all().map(i => i.json);
const allUsers = Array.isArray(users[0]) ? users[0] : users;
const dateStr = $('Build Query').first().json.yesterdayStr;

// --- Deduplicate: count INTERACTIONS not raw message rows ---
// Each workflow interaction logs multiple rows (user msg + assistant msg + conversation record)
// We count unique interactions by: one count per (user_id, message_type, 10-min window)
// This collapses duplicate logs from the same interaction

const outbound = allMessages.filter(m => m.direction === 'outbound');

function getWindowKey(m) {
  const ts = new Date(m.sent_at || 0);
  // Round to 10-min window
  const window = new Date(Math.floor(ts.getTime() / 600000) * 600000);
  return m.user_id + ':' + m.message_type + ':' + window.toISOString();
}

const seenWindows = new Set();
const uniqueInteractions = [];
for (const m of outbound) {
  const key = getWindowKey(m);
  if (!seenWindows.has(key)) {
    seenWindows.add(key);
    uniqueInteractions.push(m);
  }
}

// Count by message_type
const byType = {};
for (const m of uniqueInteractions) {
  const t = m.message_type || 'unknown';
  byType[t] = (byType[t] || 0) + 1;
}

// Active users
const activeUserIds = new Set(uniqueInteractions.map(m => m.user_id).filter(Boolean));

// Engaged users (initiated interaction)
const inbound = allMessages.filter(m => m.direction === 'inbound');
const inboundDeduped = [];
const seenInbound = new Set();
for (const m of inbound) {
  const key = getWindowKey(m);
  if (!seenInbound.has(key)) {
    seenInbound.add(key);
    inboundDeduped.push(m);
  }
}
const engagedUserIds = new Set(inboundDeduped.map(m => m.user_id).filter(Boolean));

// Format type counts
const typeLabels = {
  'digest': ':sunrise: Morning Digest',
  'meeting_prep': ':calendar: Meeting Brief',
  'meeting_recap': ':clipboard: Meeting Recap',
  'followup_prompt': ':email: Follow-up Prompt',
  'conversation': ':speech_balloon: DM Conversation',
  'slash_command': ':zap: Slash Command (/bs)',
  'silence_alert': ':no_bell: Silence Alert',
  'deal_watch': ':mag: Deal Watch',
  'announcement': ':mega: Announcement',
};

const sortedTypes = Object.entries(byType).sort((a, b) => b[1] - a[1]);
const typeLines = sortedTypes.map(([type, count]) => {
  const label = typeLabels[type] || type;
  return label + ': *' + count + '*';
}).join('\n');

const totalInteractions = uniqueInteractions.length;
const totalUsers = allUsers.length;
const activeCount = activeUserIds.size;
const engagedCount = engagedUserIds.size;
const adoptionRate = totalUsers > 0 ? Math.round((activeCount / totalUsers) * 100) : 0;

const inactiveUsers = allUsers.filter(u => !activeUserIds.has(u.id));
const inactiveCount = inactiveUsers.length;

const dateDisplay = new Date(dateStr + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

// --- Skill usage from inbound commands ---
const skillPatterns = {
  'recap': /^(recap|followup|follow-up|follow up)\b/i,
  'brief': /^brief\b/i,
  'meet': /^(meet|prep|meeting brief|meeting prep)\b/i,
  'insights': /^insights?\b/i,
  'presentation': /^(presentation|slide|slides|deck)\b/i,
  'bbr': /^(bbr|pbr|business review)\b/i,
  'stakeholders': /^stakeholders?\b/i,
  'silence': /^silence\b/i,
  'help': /^help\b/i,
  'rename': /^rename\b/i,
  'emoji': /^emoji\b/i,
  'persona': /^persona\b/i,
  'scope': /^scope\b/i,
  'focus': /^focus\b/i,
};

const skillCounts = {};
for (const m of inboundDeduped) {
  const text = (m.content || '').trim().toLowerCase();
  for (const [skill, pattern] of Object.entries(skillPatterns)) {
    if (pattern.test(text)) {
      skillCounts[skill] = (skillCounts[skill] || 0) + 1;
      break;
    }
  }
}

// Count natural language questions (inbound that didn't match any skill)
let nlQuestions = 0;
for (const m of inboundDeduped) {
  const text = (m.content || '').trim().toLowerCase();
  let matched = false;
  for (const pattern of Object.values(skillPatterns)) {
    if (pattern.test(text)) { matched = true; break; }
  }
  if (!matched && text.length > 3) nlQuestions++;
}
if (nlQuestions > 0) skillCounts['ask (natural language)'] = nlQuestions;

const skillLabels = {
  'recap': ':clipboard: Recap / Follow-up',
  'brief': ':sunrise: Brief',
  'meet': ':calendar: Meeting Prep',
  'insights': ':mag: Insights',
  'presentation': ':bar_chart: Presentation',
  'bbr': ':briefcase: Business Review',
  'stakeholders': ':busts_in_silhouette: Stakeholders',
  'silence': ':no_bell: Silence Check',
  'help': ':question: Help',
  'ask (natural language)': ':speech_balloon: Ask (natural language)',
  'rename': ':pencil2: Rename',
  'emoji': ':art: Emoji',
  'persona': ':performing_arts: Persona',
  'scope': ':dart: Scope',
  'focus': ':eye: Focus',
};

const sortedSkills = Object.entries(skillCounts).sort((a, b) => b[1] - a[1]);
const skillLines = sortedSkills
  .filter(([skill]) => !['rename', 'emoji', 'persona', 'scope', 'focus', 'help'].includes(skill))
  .map(([skill, count]) => {
    const label = skillLabels[skill] || skill;
    return label + ': *' + count + '*';
  }).join('\n');

// --- CRM actions from metadata ---
// Check outbound messages with metadata containing action indicators
let saveToSfCount = 0;
let createTaskCount = 0;
let draftFollowupCount = 0;

for (const m of allMessages) {
  let meta = m.metadata || {};
  if (typeof meta === 'string') { try { meta = JSON.parse(meta); } catch(e) { meta = {}; } }

  const mtype = m.message_type || '';
  const content = (m.content || '').toLowerCase();

  // Count recap saves (logged as meeting_recap with save indicator)
  if (content.includes('recap saved to salesforce') || content.includes('save_recap')) saveToSfCount++;
  if (content.includes('task created in salesforce') || content.includes('create_task')) createTaskCount++;
  if (mtype === 'followup_draft' || content.includes('draft follow-up') || content.includes('followup_draft')) draftFollowupCount++;
}

// Build blocks
const blocks = [
  {
    type: "header",
    text: { type: "plain_text", text: ":bar_chart: Assistant Usage Report", emoji: true }
  },
  {
    type: "context",
    elements: [{ type: "mrkdwn", text: dateDisplay }]
  },
  { type: "divider" },
  {
    type: "section",
    fields: [
      { type: "mrkdwn", text: "*Interactions*\n" + totalInteractions },
      { type: "mrkdwn", text: "*Active Users*\n" + activeCount + " of " + totalUsers + " (" + adoptionRate + "%)" },
      { type: "mrkdwn", text: "*User-Initiated*\n" + engagedCount + " users" },
      { type: "mrkdwn", text: "*Inactive Yesterday*\n" + inactiveCount + " users" },
    ]
  },
  { type: "divider" },
  {
    type: "section",
    text: { type: "mrkdwn", text: "*Interactions by Type*\n" + typeLines }
  },
];

// Top 5 most active users
const userInteractionCount = {};
for (const m of uniqueInteractions) {
  if (m.user_id) userInteractionCount[m.user_id] = (userInteractionCount[m.user_id] || 0) + 1;
}
const topUsers = Object.entries(userInteractionCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([uid, count]) => {
    const user = allUsers.find(u => u.id === uid);
    const name = user ? (user.assistant_name || user.email.split('@')[0]) : uid.substring(0, 8);
    return name + ': ' + count + ' interactions';
  });

if (topUsers.length > 0) {
  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*Most Active Assistants*\n" + topUsers.join('\n') }
  });
}

// Skills section
if (skillLines) {
  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*Skills Used*\n" + skillLines }
  });
}

// CRM Actions section
const crmTotal = saveToSfCount + createTaskCount + draftFollowupCount;
if (crmTotal > 0) {
  const crmLines = [];
  if (saveToSfCount > 0) crmLines.push(':salesforce: Save to CRM: *' + saveToSfCount + '*');
  if (createTaskCount > 0) crmLines.push(':memo: Create Task: *' + createTaskCount + '*');
  if (draftFollowupCount > 0) crmLines.push(':email: Draft Follow-up: *' + draftFollowupCount + '*');
  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*CRM Actions*\n" + crmLines.join('\n') }
  });
}

// --- User Conversations (inbound messages) ---
const userConversations = [];
for (const m of inboundDeduped) {
  const text = (m.content || '').trim();
  if (text.length < 2) continue;
  const user = allUsers.find(u => u.id === m.user_id);
  const name = user ? (user.assistant_name || user.email.split('@')[0]) : 'Unknown';
  const ts = new Date(m.sent_at);
  const timeStr = ts.toLocaleTimeString('en-US', { timeZone: 'America/Los_Angeles', hour: 'numeric', minute: '2-digit' });
  userConversations.push({ name, text: text.substring(0, 100), timeStr, ts });
}
userConversations.sort((a, b) => a.ts - b.ts);

if (userConversations.length > 0) {
  blocks.push({ type: "divider" });
  const convLines = userConversations.slice(0, 20).map(c => {
    const truncated = c.text.length >= 100 ? c.text + '...' : c.text;
    return `${c.timeStr} \u2022 *${c.name}*: ${truncated}`;
  }).join('\n');
  const headerText = userConversations.length > 20
    ? `*User Conversations* (${userConversations.length} total, showing 20)`
    : `*User Conversations* (${userConversations.length})`;
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: headerText + '\n' + convLines }
  });
}

blocks.push({
  type: "context",
  elements: [{ type: "mrkdwn", text: "People.ai Assistant Analytics \u2022 " + totalUsers + " onboarded users \u2022 " + allMessages.length + " raw msg rows deduplicated to " + totalInteractions + " interactions" }]
});

const notificationText = 'Assistant Usage: ' + totalInteractions + ' interactions, ' + activeCount + ' active users (' + adoptionRate + '%)';

return [{ json: { blocks: JSON.stringify(blocks), notificationText } }];

